html:
{% set s = frappe.get_doc("WAFD Print Settings") %}
{% set logo = doc.company_logo or s.company_logo or "/assets/wafd_one/images/wafd-almadinah-official.png" %}
{% set signature = doc.signature_image or s.default_signature %}
{% set stamp = doc.company_stamp or s.default_stamp %}
<style>
@page { size: {{ s.paper_size or 'A4' }}{% if s.orientation == 'Landscape' %} landscape{% endif %}; margin: {{ s.margin_top or 12 }}mm {{ s.margin_right or 14 }}mm {{ s.margin_bottom or 13 }}mm {{ s.margin_left or 14 }}mm; }
.undertaking { direction:rtl; text-align:right; font-family:"{{ s.font_family or 'Tahoma' }}", Arial, sans-serif; color:{{ s.text_color or '#111111' }}; font-size:{{ s.base_font_size or 13 }}px; line-height:1.75; position:relative; min-height:255mm; padding-bottom:18mm; box-sizing:border-box; }}", Arial, sans-serif; color:{{ s.text_color or '#111111' }}; font-size:{{ s.base_font_size or 13 }}px; line-height:1.75; }
.u-head { display:table; width:100%; table-layout:fixed; margin:0 0 4px; padding:0; }
.logo-wrap { display:table-cell; width:125px; vertical-align:bottom; text-align:right; }
.header-rule-wrap { display:table-cell; vertical-align:bottom; padding:0 8px 22px 0; }
.header-rule { border-bottom:0.5px solid {{ s.primary_color or '#AA8C27' }}; width:100%; height:1px; }}px solid {{ s.primary_color or '#AA8C27' }}; padding-top:10px; display:flex; align-items:center; justify-content:space-between; margin-bottom:4px; }
.logo { width:112px; max-height:112px; object-fit:contain; height:auto; display:block; }}; font-size:10px; text-align:left; direction:ltr; }
.undertaking h1 { text-align:center; font-size:{{ s.title_font_size or 18 }}px; text-decoration:underline; margin:6px 0 10px; color:{{ s.text_color or '#111111' }}; }
.meta { display:flex; justify-content:space-between; font-size:11px; margin-bottom:4px; }
.party { margin:7px 0; }.party-title { font-weight:700; font-size:14px; }.terms { margin:8px 0 0; padding-right:20px; }.terms li { padding-right:3px; margin-bottom:2px; }.closing { margin-top:7px; }
.sign { margin-top:12px; width:100%; }.sign td { width:50%; text-align:center; vertical-align:top; }.sign-img { max-width:120px; max-height:60px; object-fit:contain; }.stamp-img { max-width:120px; max-height:90px; object-fit:contain; }
.footer { position:fixed; left:0; right:0; bottom:-8mm; border-top:0.5px solid {{ s.primary_color or '#AA8C27' }}; padding-top:4px; text-align:center; direction:rtl; color:{{ s.primary_color or '#AA8C27' }}; font-size:9.5px; line-height:1.4; background:#fff; }}; margin-top:10px; padding-top:5px; text-align:center; direction:ltr; color:{{ s.primary_color or '#AA8C27' }}; font-size:10px; }
.watermark-text { position:fixed; opacity:{{ s.watermark_opacity or 0.05 }}; font-size:100px; transform:rotate(-25deg); top:42%; right:20%; z-index:-1; }
.watermark-logo { position:fixed; opacity:{{ s.watermark_opacity or 0.05 }}; width:360px; max-height:360px; object-fit:contain; top:30%; right:25%; z-index:-1; }
</style>
<div class="undertaking">
{% if s.show_watermark %}{% if s.watermark_logo %}<img class="watermark-logo" src="{{ frappe.utils.get_url(s.watermark_logo) }}">{% else %}<div class="watermark-text">{{ s.watermark_text or 'وفد' }}</div>{% endif %}{% endif %}
<div class="u-head"><div class="logo-wrap"><img class="logo" src="{{ frappe.utils.get_url(logo) }}"></div><div class="header-rule-wrap"><div class="header-rule"></div></div></div>
<h1>{{ s.document_title or 'تعهد والتزام إعاشة' }}</h1>
<div class="meta">{% if s.show_reference_number %}<span><b>رقم التعهد:</b> {{ doc.name }}</span>{% endif %}<span><b>التاريخ:</b> {{ frappe.utils.formatdate(doc.undertaking_date, 'yyyy/MM/dd') }}</span></div>
<p><b>{{ s.intro_text or 'الحمد لله، والصلاة والسلام على رسول الله، وبعد:' }}</b></p><p>{{ s.agreement_text or 'فقد تم الاتفاق على هذا التعهد بين:' }}</p>
<div class="party"><div class="party-title">الطرف الأول:</div>{{ doc.company_name }}، بموجب السجل التجاري رقم ({{ doc.company_cr }})، ويمثلها السيد/ {{ doc.company_representative }}.</div>
<div class="party"><div class="party-title">الطرف الثاني:</div>{{ doc.second_party_name }}{% if doc.second_party_cr %}، سجل تجاري رقم ({{ doc.second_party_cr }}){% endif %}{% if doc.second_party_representative %}، ويمثلها السيد/ {{ doc.second_party_representative }}{% endif %}، ويشار إليها في هذا التعهد بـ(الطرف الثاني).</div>
<p><b>حيث اتفق الطرفان على الآتي:</b></p>
<ol class="terms"><li>يقوم الطرف الأول بتأمين وجبات ({{ (doc.meal_types or '').replace('\n', ' – ') }}) لعدد ({{ doc.beneficiary_count }}) مستفيد{% if doc.nationality %} من الجنسية {{ doc.nationality }}{% endif %}.</li><li>موقع التوريد: {{ doc.supply_location or doc.hotel }}.</li><li>مدة التعهد من تاريخ {{ frappe.utils.formatdate(doc.start_date, 'yyyy/MM/dd') }}م وحتى {{ frappe.utils.formatdate(doc.end_date, 'yyyy/MM/dd') }}م.</li><li>يتعهد الطرفان بصحة البيانات المدونة أعلاه.</li><li>يلتزم الطرفان بالمواعيد المحددة في تقديم الوجبات دون تأخير.</li><li>يحق للطرف الأول المطالبة بإلغاء التعهد والمطالبة بالمبالغ المتبقية في حالة زيادة الأعداد أو اختلاف البيانات المدونة، ولا يتم تعديل أي بند من القائمة أو جدول المواعيد إلا بموافقة كتابية.</li><li>يلتزم الطرف الثاني بتأمين عمالة بشهادات صحية للتوريد للفندق، ما لم ينص العقد على خلاف ذلك.</li><li>يجب على الفندق التدقيق والتأكد من صحة البيانات، وهي على مسؤولية الفندق في حالة عدم مطابقتها.</li><li>يحق للفندق رفض التعهد في حالة عدم صحة بيانات الأعداد أو الأيام أو الجنسية.</li><li>يلتزم الطرف الأول بتسليم الفندق صورة من الأوراق الرسمية المطلوبة، بما في ذلك السجل التجاري ورخصة البلدية والعقد الخاص بالتغذية متى طُلبت.</li></ol>
{% if doc.additional_terms %}<div><b>بنود إضافية:</b>{{ doc.additional_terms }}</div>{% endif %}{% if doc.service_notes %}<p><b>ملاحظات الخدمة:</b> {{ doc.service_notes }}</p>{% endif %}
{% if s.closing_text %}<p class="closing">{{ s.closing_text }}</p>{% endif %}
<table class="sign"><tr><td><b>الطرف الأول</b><br>{{ doc.company_name }}<br>{{ doc.authorized_signatory or s.signatory_name }}<br>{{ doc.signatory_title or s.signatory_title or '' }}<br>{% if signature %}<img class="sign-img" src="{{ frappe.utils.get_url(signature) }}">{% endif %}</td>{% if s.show_second_party_signature %}<td><b>الطرف الثاني</b><br>{{ doc.second_party_name }}<br><br>التوقيع: ____________________</td>{% else %}<td><b>الختم</b><br>{% if stamp %}<img class="stamp-img" src="{{ frappe.utils.get_url(stamp) }}">{% else %}<br><br>____________________{% endif %}</td>{% endif %}</tr></table>
<div class="footer">{% if s.footer_text %}{{ s.footer_text }}{% endif %}{% if doc.company_phone %} &nbsp; | &nbsp; هاتف: {{ doc.company_phone }}{% endif %}{% if doc.company_email %} &nbsp; | &nbsp; {{ doc.company_email }}{% endif %}</div></div>
